import{_ as o,c as a,o as e,a2 as r}from"./chunks/framework.CHomSxuB.js";const n="/assets/t6_cpplatform_fvml52uuuhgzdgqj9pqx3q1782472024.gZJf9Dsq.jpg",c=JSON.parse('{"title":"半小时讲透Token（轻科技）","description":"","frontmatter":{"title":"半小时讲透Token（轻科技）","author":"一介草民","cover":"../public/t6_cpplatform_fvml52uuuhgzdgqj9pqx3q1782472024.jpg"},"headers":[],"relativePath":"看书/半小时讲透Token.md","filePath":"看书/半小时讲透Token.md"}'),l={name:"看书/半小时讲透Token.md"};function i(u,t,q,s,h,d){return e(),a("div",null,t[0]||(t[0]=[r('<h1 id="半小时讲透token-轻科技" tabindex="-1">半小时讲透Token（轻科技） <a class="header-anchor" href="#半小时讲透token-轻科技" aria-label="Permalink to &quot;半小时讲透Token（轻科技）&quot;">​</a></h1><p><img src="'+n+'" alt="封面"></p><blockquote><p>作者：一介草民 · 轻科技系列</p></blockquote><h2 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;写在前面&quot;">​</a></h2><p>如果说&quot;千瓦时&quot;定义了电力时代、&quot;桶&quot;定义了石油时代，那么 <strong>Token</strong> 就是人工智能时代的核心计量单位。</p><p>这本《半小时讲透Token（轻科技）》用极短的篇幅，把 AI 时代最容易被忽视的&quot;度量衡&quot;讲透了： Token 不只是大模型处理文字的最小片段，更是一把<strong>丈量新经济</strong>的尺子。</p><hr><h2 id="全书脉络" tabindex="-1">全书脉络 <a class="header-anchor" href="#全书脉络" aria-label="Permalink to &quot;全书脉络&quot;">​</a></h2><p>全书分五章一结语，层层递进：</p><table tabindex="0"><thead><tr><th>章节</th><th>主题</th><th>一句话回答</th></tr></thead><tbody><tr><td>第一章　认识 Token</td><td>AI 世界的&quot;原子&quot;</td><td>Token 是什么、怎么计费、为什么不是所有 Token 都一样值钱</td></tr><tr><td>第二章　看懂产业</td><td>谁在造&quot;Token 工厂&quot;</td><td>算力 = 电厂，大模型 = 智力批发，云巨头 = 自来水管公司</td></tr><tr><td>第三章　抓住红利</td><td>当智力比水还便宜</td><td>暴力计算可行、成本结构变化、效率差就是利润差</td></tr><tr><td>第四章　避开陷阱</td><td>聊天框撑不起一门生意</td><td>单纯答疑只是&quot;查信息&quot;，能&quot;办成事&quot;才是产品</td></tr><tr><td>第五章　找到方向</td><td>Agent 与结果交付</td><td>从&quot;等用户问&quot;到&quot;自己把事做完&quot;，未来属于编排者</td></tr></tbody></table><hr><h2 id="第一章-认识-token" tabindex="-1">第一章　认识 Token <a class="header-anchor" href="#第一章-认识-token" aria-label="Permalink to &quot;第一章　认识 Token&quot;">​</a></h2><h3 id="_1-1-万物皆可打碎-——-ai-眼中的世界长什么样" tabindex="-1">1.1 万物皆可打碎 —— AI 眼中的世界长什么样？ <a class="header-anchor" href="#_1-1-万物皆可打碎-——-ai-眼中的世界长什么样" aria-label="Permalink to &quot;1.1 万物皆可打碎 —— AI 眼中的世界长什么样？&quot;">​</a></h3><p>Token 是大模型处理信息的<strong>最小语义片段</strong>，不是字，也不是词，是 AI 自己学出来的&quot;文字碎片&quot;：</p><ul><li><strong>英文</strong>：<code>Artificial intelligence is transforming our world</code> ≈ 8 个 Token</li><li><strong>中文</strong>：<code>人工智能正在改变我们的世界</code> ≈ 12 个 Token</li><li>经验换算：英文 1 Token ≈ 0.75 单词；中文 1 Token ≈ 1.5~2 个汉字</li><li>切分靠 <strong>Tokenizer</strong>，训练靠 <strong>BPE（字节对编码）</strong> —— 像快递打包员一样把高频组合并成大包</li></ul><h3 id="_1-2-从-买软件-到-买智力" tabindex="-1">1.2 从&quot;买软件&quot;到&quot;买智力&quot; <a class="header-anchor" href="#_1-2-从-买软件-到-买智力" aria-label="Permalink to &quot;1.2 从&quot;买软件&quot;到&quot;买智力&quot;&quot;">​</a></h3><p>计费方式的变革，背后是商业逻辑的彻底切换：</p><table tabindex="0"><thead><tr><th>时代</th><th>卖的是什么</th><th>计费单位</th></tr></thead><tbody><tr><td>软件时代</td><td>许可证</td><td>套/账号</td></tr><tr><td>SaaS 时代</td><td>服务订阅</td><td>月/账号</td></tr><tr><td>AI 时代</td><td>智力调用</td><td><strong>Token</strong></td></tr></tbody></table><p>钱不再为&quot;功能&quot;买单，而为&quot;推理量&quot;买单。</p><h3 id="_1-3-不是所有-token-都一样值钱" tabindex="-1">1.3 不是所有 Token 都一样值钱 <a class="header-anchor" href="#_1-3-不是所有-token-都一样值钱" aria-label="Permalink to &quot;1.3 不是所有 Token 都一样值钱&quot;">​</a></h3><ul><li><strong>输入 Token</strong> 和 <strong>输出 Token</strong> 价差巨大（输出贵 3~5 倍）</li><li><strong>思考 Token</strong>（CoT、ReAct 内部推理）用户看不见，却在烧钱</li><li><strong>缓存命中 / 未命中</strong>直接决定成本差一个数量级</li><li><strong>模型分层</strong>：不同档位模型的&quot;单 Token 价格&quot;差出几十倍</li></ul><hr><h2 id="第二章-看懂产业" tabindex="-1">第二章　看懂产业 <a class="header-anchor" href="#第二章-看懂产业" aria-label="Permalink to &quot;第二章　看懂产业&quot;">​</a></h2><h3 id="_2-1-算力-——-这个时代最贵的-电厂" tabindex="-1">2.1 算力 —— 这个时代最贵的&quot;电厂&quot; <a class="header-anchor" href="#_2-1-算力-——-这个时代最贵的-电厂" aria-label="Permalink to &quot;2.1 算力 —— 这个时代最贵的&quot;电厂&quot;&quot;">​</a></h3><blockquote><p>&quot;门票动辄几十亿。&quot;</p></blockquote><p>算力就是 AI 时代的发电厂，资本壁垒极高： H100/H200 集群、超大规模数据中心、长协电力 —— 不再是互联网公司的菜，是<strong>国家级重资产</strong>。</p><h3 id="_2-2-大模型-——-卖-智力批发-的人-正在打价格战" tabindex="-1">2.2 大模型 —— 卖&quot;智力批发&quot;的人，正在打价格战 <a class="header-anchor" href="#_2-2-大模型-——-卖-智力批发-的人-正在打价格战" aria-label="Permalink to &quot;2.2 大模型 —— 卖&quot;智力批发&quot;的人，正在打价格战&quot;">​</a></h3><ul><li>训练一次顶尖模型的成本以<strong>亿美元</strong>计</li><li>OpenAI、Anthropic、Google、DeepSeek、阿里、字节……所有人都在卷<strong>单 Token 降价</strong></li><li>卖&quot;通用智力&quot;的毛利越来越薄，模型层正在被上下挤压</li></ul><h3 id="_2-3-云巨头-——-铺设-智力自来水管-的人-才是最后的赢家" tabindex="-1">2.3 云巨头 —— 铺设&quot;智力自来水管&quot;的人，才是最后的赢家？ <a class="header-anchor" href="#_2-3-云巨头-——-铺设-智力自来水管-的人-才是最后的赢家" aria-label="Permalink to &quot;2.3 云巨头 —— 铺设&quot;智力自来水管&quot;的人，才是最后的赢家？&quot;">​</a></h3><p>AWS、Azure、阿里云、火山引擎…… <strong>Token 最终会像水电一样从管道里流出</strong>。 云厂商把&quot;算力 + 模型 + 工具链&quot;打包成按 Token 计价的云服务，吃掉产业链最大一块利润。</p><hr><h2 id="第三章-抓住红利" tabindex="-1">第三章　抓住红利 <a class="header-anchor" href="#第三章-抓住红利" aria-label="Permalink to &quot;第三章　抓住红利&quot;">​</a></h2><h3 id="_3-1-当智力比水还便宜-世界会怎样" tabindex="-1">3.1 当智力比水还便宜，世界会怎样？ <a class="header-anchor" href="#_3-1-当智力比水还便宜-世界会怎样" aria-label="Permalink to &quot;3.1 当智力比水还便宜，世界会怎样？&quot;">​</a></h3><blockquote><p>杰文斯悖论在 AI 时代重演：效率提升不会让总消耗下降，反而让总消耗<strong>暴涨</strong>。</p></blockquote><p>廉价智力 → 更多场景被解锁 → 总 Token 消耗指数级增长。</p><h3 id="_3-2-以前要省着用-现在可以暴力计算" tabindex="-1">3.2 以前要省着用，现在可以暴力计算 <a class="header-anchor" href="#_3-2-以前要省着用-现在可以暴力计算" aria-label="Permalink to &quot;3.2 以前要省着用，现在可以暴力计算&quot;">​</a></h3><ul><li>长上下文、多轮 Agent、Tool Use、CoT 反思……以前&quot;省 Token&quot;是核心能力</li><li>现在 Token 单价暴跌，<strong>&quot;敢用&quot;比&quot;省着用&quot;更能产出价值</strong></li></ul><h3 id="_3-3-同样用-ai-为什么有人的成本比你低一半" tabindex="-1">3.3 同样用 AI，为什么有人的成本比你低一半？ <a class="header-anchor" href="#_3-3-同样用-ai-为什么有人的成本比你低一半" aria-label="Permalink to &quot;3.3 同样用 AI，为什么有人的成本比你低一半？&quot;">​</a></h3><ul><li><strong>Prompt 工程</strong>：结构化提示词显著减少无效输出</li><li><strong>模型路由</strong>：简单任务用小模型，复杂任务才用大模型</li><li><strong>缓存 + 批处理</strong>：重复内容走命中，单次请求打批量</li><li><strong>RAG 替代长上下文</strong>：检索永远比&quot;全塞进去&quot;便宜</li></ul><hr><h2 id="第四章-避开陷阱" tabindex="-1">第四章　避开陷阱 <a class="header-anchor" href="#第四章-避开陷阱" aria-label="Permalink to &quot;第四章　避开陷阱&quot;">​</a></h2><h3 id="_4-1-一个聊天框-撑不起一门生意" tabindex="-1">4.1 一个聊天框，撑不起一门生意 <a class="header-anchor" href="#_4-1-一个聊天框-撑不起一门生意" aria-label="Permalink to &quot;4.1 一个聊天框，撑不起一门生意&quot;">​</a></h3><blockquote><p>&quot;对话&quot;是 AI 能力的展示窗口，但不是产品。</p></blockquote><p>光有聊天框，没有场景、没有工作流、没有数据沉淀 —— 留存为零。</p><h3 id="_4-2-帮你查信息-和-帮你办成事-中间隔着一条河" tabindex="-1">4.2 &quot;帮你查信息&quot;和&quot;帮你办成事&quot;，中间隔着一条河 <a class="header-anchor" href="#_4-2-帮你查信息-和-帮你办成事-中间隔着一条河" aria-label="Permalink to &quot;4.2 &quot;帮你查信息&quot;和&quot;帮你办成事&quot;，中间隔着一条河&quot;">​</a></h3><ul><li><strong>查信息型产品</strong>：替代搜索引擎 → 低频、缺壁垒</li><li><strong>办成事型产品</strong>：替代员工/外包 → 高频、高 LTV</li></ul><p>能不能&quot;动手&quot;（调用工具、操作外部系统），决定了你做的是<strong>玩具</strong>还是<strong>工具</strong>。</p><h3 id="_4-3-用户用一次就走了-你的产品凭什么让他留下来" tabindex="-1">4.3 用户用一次就走了，你的产品凭什么让他留下来？ <a class="header-anchor" href="#_4-3-用户用一次就走了-你的产品凭什么让他留下来" aria-label="Permalink to &quot;4.3 用户用一次就走了，你的产品凭什么让他留下来？&quot;">​</a></h3><ul><li>没有<strong>数据沉淀</strong>，用户每次都从零开始</li><li>没有<strong>协作场景</strong>，就是一次性消费</li><li>没有<strong>结果交付</strong>，用户永远在&quot;试用&quot;，从不&quot;依赖&quot;</li></ul><hr><h2 id="第五章-找到方向" tabindex="-1">第五章　找到方向 <a class="header-anchor" href="#第五章-找到方向" aria-label="Permalink to &quot;第五章　找到方向&quot;">​</a></h2><h3 id="_5-1-什么是-agent-从-等你发问-到-自己把事做完" tabindex="-1">5.1 什么是 Agent？从&quot;等你发问&quot;到&quot;自己把事做完&quot; <a class="header-anchor" href="#_5-1-什么是-agent-从-等你发问-到-自己把事做完" aria-label="Permalink to &quot;5.1 什么是 Agent？从&quot;等你发问&quot;到&quot;自己把事做完&quot;&quot;">​</a></h3><p>Agent = <strong>大模型 + 记忆 + 工具 + 规划能力</strong></p><p>它不是更强的聊天框，而是能：</p><ol><li>自己拆解目标</li><li>自己选择工具</li><li>自己观察结果</li><li>自己迭代下一步</li></ol><h3 id="_5-2-不卖过程-卖结果-——-下一代-ai-产品的商业逻辑" tabindex="-1">5.2 不卖过程，卖结果 —— 下一代 AI 产品的商业逻辑 <a class="header-anchor" href="#_5-2-不卖过程-卖结果-——-下一代-ai-产品的商业逻辑" aria-label="Permalink to &quot;5.2 不卖过程，卖结果 —— 下一代 AI 产品的商业逻辑&quot;">​</a></h3><ul><li>过去卖&quot;软件&quot;：交付的是工具，用户自己用</li><li>过去卖&quot;服务&quot;：交付的是工时，按人天计费</li><li>未来卖&quot;结果&quot;：交付的是<strong>办成的事</strong>，按结果计价</li></ul><blockquote><p>卖过程 = 按 Token 计价的 API；卖结果 = 按业务价值计价的 Agent 服务。</p></blockquote><h3 id="_5-3-当无数个-agent-开始协作-一个新的世界诞生了" tabindex="-1">5.3 当无数个 Agent 开始协作，一个新的世界诞生了 <a class="header-anchor" href="#_5-3-当无数个-agent-开始协作-一个新的世界诞生了" aria-label="Permalink to &quot;5.3 当无数个 Agent 开始协作，一个新的世界诞生了&quot;">​</a></h3><ul><li>单 Agent → 多 Agent 协作（Orchestrator + Workers）</li><li>Agent 之间通过 <strong>MCP、A2A 协议</strong>互联</li><li>个人 / 小团队可以指挥一群 Agent 干完以前大公司的活</li></ul><hr><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><blockquote><p>这些篇章共同描绘了一幅蓝图：<strong>未来属于那些能深入具体领域、定义有价值任务，并指挥无数 Agent 协同工作的人。</strong></p></blockquote><p>整本书半小时就能读完，但读完之后你会重新理解三件事：</p><ol><li><strong>Token 是新度量衡</strong> —— 你的每一次 AI 调用，都在被这把新尺子丈量</li><li><strong>Agent 是新交付物</strong> —— 不再卖工具，卖办成的事</li><li><strong>编排者是新角色</strong> —— 价值从&quot;写代码&quot;迁移到&quot;调度 Agent&quot;</li></ol><hr><h2 id="我的总结" tabindex="-1">我的总结 <a class="header-anchor" href="#我的总结" aria-label="Permalink to &quot;我的总结&quot;">​</a></h2><blockquote><p><strong>从&quot;码农&quot;到&quot;agent&quot;编排者。吃透业务，把控过程，交付结果。</strong></p></blockquote><p>读完这本书，最大的冲击不是&quot;Token 是什么&quot;，而是**&quot;我的位置在哪&quot;**。</p><p>以前我们写代码，是把业务规则翻译成 if-else；以后我们编排 Agent，是把业务目标拆解成可执行的任务图。 <strong>码农交付的是过程，编排者交付的是结果。</strong></p><ul><li><strong>吃透业务</strong>：Agent 没有业务理解就只能瞎跑，业务深度才是不可替代的护城河</li><li><strong>把控过程</strong>：Token 流、工具调用、记忆状态、失败重试 —— 编排者必须看得见、可干预、可调优</li><li><strong>交付结果</strong>：不为&quot;调用了多少 Token&quot;买单，要为&quot;问题有没有被解决&quot;负责</li></ul><p><strong>Token 在贬值，结果在升值。</strong> 下一个十年，比拼的不再是写了多少行代码，而是交付了多少&quot;被办成的事&quot;。</p>',72)]))}const k=o(l,[["render",i]]);export{c as __pageData,k as default};
